import{_ as e,o as t,c as o,Q as i}from"./chunks/framework.c4d6cd72.js";const b=JSON.parse('{"title":"Release Notes","description":"","frontmatter":{"sidebar":false,"prev":false,"next":false},"headers":[],"relativePath":"release-notes/index.md","filePath":"release-notes/index.md"}'),r={name:"release-notes/index.md"},n=i('<h1 id="release-notes" tabindex="-1">Release Notes <a class="header-anchor" href="#release-notes" aria-label="Permalink to &quot;Release Notes&quot;">​</a></h1><h2 id="version-1-3-2024-06-05" tabindex="-1">Version 1.3 (2024-06-05) <a class="header-anchor" href="#version-1-3-2024-06-05" aria-label="Permalink to &quot;Version 1.3 (2024-06-05)&quot;">​</a></h2><h3 id="main-changes" tabindex="-1">Main Changes <a class="header-anchor" href="#main-changes" aria-label="Permalink to &quot;Main Changes&quot;">​</a></h3><ul><li><p>New <a href="https://app.fraudintelligencelimited.com" target="_blank" rel="noreferrer">FIB Web App</a> user interface.</p><blockquote><p>Documented here:<br><a href="./../overview/web-interface.html">Web App UI</a></p></blockquote></li><li><p>Added automatic generation of the user key pairs. These are now generated during user registration and can be accessed from the <a href="./../overview/web-interface.html#profile">Profile</a> screen of the new <a href="https://app.fraudintelligencelimited.com" target="_blank" rel="noreferrer">Web App</a>.</p><blockquote><p>Documented here:<br><a href="./../overview/web-interface.html">Web App UI</a> — <a href="./../overview/web-interface.html#akp">&#39;Authorization&#39; key pair</a> and <a href="./../overview/web-interface.html#bkp">&#39;Blockchain&#39; key pair</a> subtopics.</p></blockquote></li><li><p>Flagging a contribution uploaded by the same peer no longer provides token rewards.</p><blockquote><p>Documented here:<br><a href="./../tutorials-web/flagging-fraud-data.html">Tutorials: Web App &gt; Flagging fraud data</a> — Added new <strong>Note</strong> callout.<br><a href="./../tutorials-api/flagging-a-contribution.html">Tutorials: API &gt; Flagging fraud data</a> — Added new <strong>Note</strong> callout.</p></blockquote></li><li><p>Contributions with a set confidence index value can be downloaded repeatedly with no extra charge to the user&#39;s <a href="./../overview/tokenomics.html#token-balance">token balance</a>, even if the value has changed since the first retrieval.</p><blockquote><p>Documented here:<br><a href="./../overview/tokenomics.html#confidence-index">Overview &gt; Tokenomics</a> — Updated the existing <strong>Note</strong> callout.</p></blockquote></li><li><p>Added support of dial-in codes for international networks (<code>+882</code> and <code>+883</code>).</p></li></ul><h3 id="api-changes" tabindex="-1">API Changes <a class="header-anchor" href="#api-changes" aria-label="Permalink to &quot;API Changes&quot;">​</a></h3><ul><li><p>Removed the <code>premium-provider-controller</code> and all of its operations/endpoints.</p></li><li><p>Removed the <code>peer-controller</code>: <strong>Requesting peer details</strong> operation.</p></li><li><p>Added the <code>auth-controller</code>: <strong>Logging a user out of the system</strong> operation.</p><blockquote><p>Documented here:<br><a href="./../api-specification/auth-controller/logging-a-user-out-of-the-system.html">API Specification &gt; Logging a user out of the system</a> — new topic.</p></blockquote></li><li><p>Added the <code>peer-controller</code>: <strong>Retrieving user details</strong> operation.</p><blockquote><p>Documented here:<br><a href="./../api-specification/peer-controller/retrieving-user-details.html">API Specification &gt; Retrieving user details</a> — new topic.</p></blockquote></li><li><p>Added the <code>contribution-controller</code>: <strong>Retrieving pricing rate</strong> operation.</p><blockquote><p>Documented here:<br><a href="./../api-specification/contribution-controller/retrieving-pricing-rate.html">API Specification &gt; Retrieving pricing rate</a> — new topic.</p></blockquote></li><li><p>Added the <code>contribution-controller</code>: <strong>Retrieving rewards rate</strong> operation.</p><blockquote><p>Documented here:<br><a href="./../api-specification/contribution-controller/retrieving-rewards-rate.html">API Specification &gt; Retrieving rewards rate</a> — new topic.</p></blockquote></li><li><p>Updated the <code>contribution-controller</code>: <strong>Retrieving contributions</strong> operation so that its API responses contain new data.</p><blockquote><p>Documented here:<br><a href="./../api-specification/contribution-controller/retrieving-contributions.html">API Specification &gt; Retrieving contributions</a> — <code>newWithConfidenceIndex</code>, <code>balanceLeft</code>, <code>contributionsNotReturned</code>, <code>contributionsNotReturnedCost</code>, <code>timestamp</code>, <code>flagTimestamp</code> fields added to, and <code>premium</code> field removed from the <strong>Output/response structure</strong></p></blockquote></li></ul><h3 id="other-improvements" tabindex="-1">Other Improvements <a class="header-anchor" href="#other-improvements" aria-label="Permalink to &quot;Other Improvements&quot;">​</a></h3><ul><li><p>Transitioned the FIB platform to the latest stable version of Iroha 2.</p></li><li><p>Transferred access management of the stored contributions fully to the blockchain level of the system.</p></li><li><p>Unified terminology across all API requests and responses.</p></li><li><p>Added a check for the uniqueness of the phone number entered during user registration.</p></li><li><p>Optimized the data structures of all internal components, including the blockchain level.</p></li></ul><h3 id="bug-fixes" tabindex="-1">Bug Fixes <a class="header-anchor" href="#bug-fixes" aria-label="Permalink to &quot;Bug Fixes&quot;">​</a></h3><ul><li><p>Fixed a bug with blockchain nodes not reporting connectivity issues.</p></li><li><p>Fixed a bug with the request body validation process errors containing non-human-readable messages.</p></li><li><p>Fixed a bug that allowed users to flag irrelevant or nonexistent contributions.</p></li></ul><h2 id="version-1-2-2023-12-14" tabindex="-1">Version 1.2 (2023-12-14) <a class="header-anchor" href="#version-1-2-2023-12-14" aria-label="Permalink to &quot;Version 1.2 (2023-12-14)&quot;">​</a></h2><h3 id="main-changes-1" tabindex="-1">Main Changes <a class="header-anchor" href="#main-changes-1" aria-label="Permalink to &quot;Main Changes&quot;">​</a></h3><ul><li><p>When submitting a contribution or a flag, the API response now displays the reward for the said submission in tokens.</p><blockquote><p>Documented here:<br><a href="./../api-specification/contribution-controller/retrieving-contributions.html">API Specification &gt; Retrieving contributions</a> — <code>confidence-score</code> added to <strong>Parameters</strong> and <strong>Output/response structure</strong> updated.</p></blockquote></li><li><p>When retrieving contributions, the API response now displays additional information.</p><blockquote><p>Documented here:<br><a href="./../overview/contributions.html#api-requests-data-structure">Overview &gt; Contributions</a> — <strong>API requests data structure</strong> updated with <code>flagger</code>, <code>self</code>, <code>old</code>, <code>new</code> and <code>creditsSpent</code> fields.<br><a href="./../api-specification/contribution-controller/retrieving-contributions.html">API Specification &gt; Retrieving contributions</a> — <strong>Output/response structure</strong> updated.</p></blockquote></li><li><p>Contributions on the blockchain now have a <code>flagger</code> value that displays the ID of a peer that flagged the contribution if it has been flagged.</p><blockquote><p>Documented here:<br><a href="./../overview/contributions.html#api-requests-data-structure">Overview &gt; Contributions</a> — <strong>Flagging contributions</strong> and <strong>API requests data structure</strong> updated.</p></blockquote></li><li><p>Added functionality related to the confidence index, a value between 1 and 100 that represents how confident the system is that a contributed fraud event is legitimate.</p><blockquote><p>Documented here:<br><a href="./../overview/tokenomics.html#confidence-index">Overview &gt; Tokenomics</a> — <strong>Confidence Index</strong> subtopic added.<br><a href="./../api-specification/contribution-controller/retrieving-contributions.html">API Specification &gt; Retrieving contributions</a> — <code>confidence-score</code> added to <strong>Parameters</strong> and <strong>Output/response structure</strong> updated.</p></blockquote></li></ul><h3 id="other-improvements-1" tabindex="-1">Other Improvements <a class="header-anchor" href="#other-improvements-1" aria-label="Permalink to &quot;Other Improvements&quot;">​</a></h3><ul><li><p>Performed an audit of the interservice communication safety, fixed known security-related vulnerabilities, updated the implemented third-party dependencies.</p></li><li><p>Indexed data on the network, enhancing the overall performance of the search engine that retrieves stored contributions.</p></li><li><p>Refactored and optimized the code structure of the query engine that can retrieve all data of any specific type.</p></li></ul><h3 id="bug-fixes-1" tabindex="-1">Bug Fixes <a class="header-anchor" href="#bug-fixes-1" aria-label="Permalink to &quot;Bug Fixes&quot;">​</a></h3><ul><li><p>Fixed a bug where leftover data with peer details remained on the network after a peer had been deleted; this caused a new peer account to be corrupted in case it was registered again with the same credentials, as well as potential issues with other peer data getting corrupted.</p></li><li><p>Fixed a bug that allowed users to find out the subscription type of any other peer.</p></li><li><p>Fixed a bug with call processing timeouts being inconsistent.</p></li></ul><h2 id="version-1-1-2023-04-27" tabindex="-1">Version 1.1 (2023-04-27) <a class="header-anchor" href="#version-1-1-2023-04-27" aria-label="Permalink to &quot;Version 1.1 (2023-04-27)&quot;">​</a></h2><p>Initial public version released with the functionality documented in our <a href="./../">Guide</a>.</p><h2 id="version-1-0-2022-12-12" tabindex="-1">Version 1.0 (2022-12-12) <a class="header-anchor" href="#version-1-0-2022-12-12" aria-label="Permalink to &quot;Version 1.0 (2022-12-12)&quot;">​</a></h2><p>Internal version not released to public.</p>',21),a=[n];function s(l,c,d,u,p,h){return t(),o("div",null,a)}const f=e(r,[["render",s]]);export{b as __pageData,f as default};
